SELECT id, category_id, name, code, icon, description, prompt_template, temperature, max_tokens,
       input_schema, output_format, module_key, status, sort_order, use_count, created_by, created_at, updated_at
FROM ai_skill

    AND category_id = #{categoryId}
    AND module_key = #{moduleKey}
    AND status = #{status}

        AND (name LIKE CONCAT('%', #{keyword}, '%') OR code LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY sort_order ASC, created_at DESC

